class Solution {
    public int hardestWorker(int n, int[][] logs) {
        int maxTime = 0;
        int maxId = 0;
        for (int i = 0; i < logs.length; i++) {
            int time = logs[i][1] - (i == 0 ? 0 : logs[i - 1][1]);
            if (time > maxTime || (time == maxTime && logs[i][0] < maxId)) {
                maxTime = time;
                maxId = logs[i][0];
            }
        }
        return maxId;
    }
}
